from pydantic import BaseModel

class HouseInput(BaseModel):

    housing_median_age: float
    # median age of houses

    total_rooms: float
    # total rooms in the area

    total_bedrooms: float
    # total bedrooms in the area

    population: float
    # population of the area

    households: float
    # number of households

    median_income: float
    # median income of residents

    ocean_proximity: str
    # NEAR BAY / INLAND / NEAR OCEAN / <1H OCEAN / ISLAND

# HouseInput validates incoming data from Postman or Streamlit
# predicted_price not included here — generated by the ML model